      if (/^What is/i.test(question)) throw new Error("Syntax error");
      throw new Error("Unknown operation");
    }

    const expr = match[1].trim();
    const tokens = expr.split(/\s+/);

    const ops = {
      'plus': (a, b) => a + b,
      'minus': (a, b) => a - b,
      'multiplied': (a, b) => a * b,
      'divided': (a, b) => a / b,
    };

    let i = 0;

    const parseNumber = () => {
      if (i >= tokens.length) throw new Error("Syntax error");
      const num = parseInt(tokens[i], 10);
      if (isNaN(num)) throw new Error("Syntax error");
      i++;
      return num;
    };

    let result = parseNumber();

    while (i < tokens.length) {
      const op = tokens[i];
      if (!(op in ops)) throw new Error("Syntax error");
      i++;
      if (op === 'multiplied' || op === 'divided') {
        if (i >= tokens.length || tokens[i] !== 'by') throw new Error("Syntax error");
        i++;
      }
      const b = parseNumber();
      result = ops[op](result, b);
    }

    return result;
  };
};

export default function define(runtime, observer) {
  const main = runtime.module();
  const $def = (pid, name, deps, fn) => main.variable(observer(name)).define(name, deps, fn).pid = pid;
  $def("_answer", "answer", [], _answer);
  return main;
}
